args.query:
SELECT date_trunc('month', createddate) AS month_start, COUNT(*) AS case_count
FROM "Case"
WHERE trim(both '#' FROM orderitemid__c) IN (
  SELECT trim(both '#' FROM id)
  FROM (
    SELECT id FROM "Case" WHERE 1=0
  ) t
)
;

